 28→    static func measureIfSlow(_ label: String, thresholdMs: Double = 4, body: () -> Void) {
 29→        guard isEnabled else { return body() }
 30→        let start = CFAbsoluteTimeGetCurrent()
 31→        body()
 32→        let ms = (CFAbsoluteTimeGetCurrent() - start) * 1000
 33→        guard ms >= thresholdMs else { return }
 34→        log(String(format: "%@ slow=%.2fms", label, ms))
 35→    }
 36→
 37→    static func measure<T>(_ label: String, body: () -> T) -> T {
 38→        guard isEnabled else { return body() }
 39→        let start = CFAbsoluteTimeGetCurrent()
 40→        let result = body()
 41→        let ms = (CFAbsoluteTimeGetCurrent() - start) * 1000
 42→        log(String(format: "%@=%.2fms", label, ms))
 43→        return result
 44→    }
 45→
 46→    @discardableResult
 47→    static func timed<T>(_ body: () -> T) -> (result: T, ms: Double) {
 48→        let start = CFAbsoluteTimeGetCurrent()
 49→        let result = body()
 50→        let ms = (CFAbsoluteTimeGetCurrent() - start) * 1000
 51→        return (result, ms)
 52→    }
