 3→/// A spread represents one or two pages displayed together in dual-page mode.
 4→enum PageSpread: Sendable, Equatable {
 5→    case single(index: Int, item: ImageItem)
 6→    case double(leadingIndex: Int, leading: ImageItem, trailingIndex: Int, trailing: ImageItem)
 7→
 8→    /// The index of the leading (first) page in the original images array.
 9→    var leadingIndex: Int {
10→        switch self {
11→        case .single(let index, _): return index
12→        case .double(let index, _, _, _): return index
13→        }
14→    }
15→
16→    /// The leading item — used as the primary reference for this spread.
17→    var leadingItem: ImageItem {
18→        switch self {
19→        case .single(_, let item): return item
20→        case .double(_, let leading, _, _): return leading
21→        }
22→    }
23→
24→    /// All items in display order (leading first).
25→    var items: [ImageItem] {
26→        switch self {
27→        case .single(_, let item): return [item]
28→        case .double(_, let leading, _, let trailing): return [leading, trailing]
29→        }
30→    }
31→
32→    /// All page indices in the original images array.
33→    var indices: [Int] {
34→        switch self {
35→        case .single(let index, _): return [index]
36→        case .double(let li, _, let ti, _): return [li, ti]
37→        }
38→    }
39→
40→    /// Check if this spread contains the given page index (no allocation).
41→    func containsPage(_ pageIndex: Int) -> Bool {
42→        switch self {
43→        case .single(let index, _):
44→            return index == pageIndex
45→        case .double(let li, _, let ti, _):
46→            return li == pageIndex || ti == pageIndex
47→        }
48→    }
49→}
